import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.CanvC6-R.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"language/index.md","filePath":"language/index.md"}'),s={name:"language/index.md"};function o(l,e,r,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Bliss is a statically typed, compiled language designed with clarity and explicitness as core principles. It assumes familiarity with general programming concepts — this documentation is a language reference, not a tutorial.</p><h2 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h2><p>Bliss favors explicitness over convenience. Types are always declared. Memory behavior is deterministic and built into the language itself. There are no implicit conversions, no hidden copies, and no surprises.</p><p>Where most languages offer flexibility, Bliss offers a contract.</p><h2 id="what-bliss-is" tabindex="-1">What Bliss Is <a class="header-anchor" href="#what-bliss-is" aria-label="Permalink to &quot;What Bliss Is&quot;">​</a></h2><ul><li>Statically typed — all types are known at compile time</li><li>Explicit — behavior is always visible at the call site</li><li>Minimal — the language core is small and consistent by design</li></ul><h2 id="what-bliss-is-not" tabindex="-1">What Bliss Is Not <a class="header-anchor" href="#what-bliss-is-not" aria-label="Permalink to &quot;What Bliss Is Not&quot;">​</a></h2><p>Bliss is an evolving language. Features will be added, and the specification will change. This documentation reflects the current state of the language and should be treated as such.</p><h2 id="a-note-on-this-documentation" tabindex="-1">A Note on This Documentation <a class="header-anchor" href="#a-note-on-this-documentation" aria-label="Permalink to &quot;A Note on This Documentation&quot;">​</a></h2><p>Each article in this reference covers exactly one language construct. Where a concept depends on another, it will be referenced explicitly. Readers are expected to be comfortable with general programming concepts such as types, functions, and control flow.</p><hr><p>Short, grounded, and doesn&#39;t make promises the language can&#39;t keep yet. Want to adjust the tone or add anything?</p>',13)])])}const g=a(s,[["render",o]]);export{u as __pageData,g as default};
